function textFromMessage(msg) {
  if (!msg || typeof msg !== 'object') return '';
  if (msg.text?.body) return String(msg.text.body).trim();
  if (msg.text) return String(msg.text).trim();
  if (msg.body) return String(msg.body).trim();
  if (msg.message) return String(msg.message).trim();
  if (msg.caption) return String(msg.caption).trim();
  return '';
}

const input = $input.first()?.json || {};
const body = input.body && typeof input.body === 'object' ? input.body : input;
const message = Array.isArray(body.messages) ? body.messages[0] : body.message || body;
const waIdRaw = message.from || body.wa_id || body.telefone || body.phone || body.from || '';
const waId = String(waIdRaw).replace(/@c\.us$/, '').trim();
const messageText = textFromMessage(message) || textFromMessage(body);
const timestampRaw = Number(message.timestamp || body.timestamp || 0);
const receivedAt = Number.isFinite(timestampRaw) && timestampRaw > 0
  ? new Date(timestampRaw * 1000).toISOString()
  : new Date().toISOString();
const eventId = String(message.id || body.event_id || body.id || `${waId}-${Date.now()}`).trim();

return [{
  json: {
    event_id: eventId,
    wa_id: waId,
    telefone: waId,
    message_text: messageText,
    tenant_id: String(body.tenant_id || $env.LARA_TENANT_ID || 'default'),
    jurisdicao: 'BR',
    canal: 'WHATSAPP',
    received_at: receivedAt,
    payload: {
      provider: body.provider || 'whatsapp',
      raw_payload: body,
      raw_message: message
    }
  }
}];

const conversa = $input.first()?.json || {};
const mensagens = Array.isArray(conversa.mensagens) ? conversa.mensagens : [];
const outbound = [...mensagens].reverse().find((msg) => {
  const direction = String(msg.direction || msg.direcao || '').toUpperCase();
  return direction === 'OUTBOUND' || String(msg.tipo || '').toLowerCase() !== 'inbound';
});
const text = String(outbound?.texto || outbound?.message_text || outbound?.mensagem || conversa.mensagem || '').trim();
const waId = String(conversa.wa_id || $node['Normaliza mensagem WhatsApp'].json.wa_id || '').trim();

return [{
  json: {
    has_response: Boolean(text && waId),
    to: waId,
    text,
    event_id: $node['Normaliza mensagem WhatsApp'].json.event_id,
    correlation_id: conversa.correlation_id || ''
  }
}];
